  "inlineSchema": "// ============================================================\n// PetCare – Schema Prisma\n// Arquitetura: User 1:N Pet 1:N CareRecord\n// ORM: Prisma | DB: MySQL\n// ============================================================\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"mysql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ============================================================\n// ENUM: Tipos de cuidado — permite filtros tipados\n// ============================================================\nenum CareType {\n  VACCINE // Vacinação\n  CONSULTATION // Consulta veterinária\n  MEDICATION // Medicamento\n  EXAM // Exame laboratorial/imagem\n  SURGERY // Cirurgia\n  GROOMING // Banho/tosa\n  OTHER // Outros\n}\n\n// ============================================================\n// ENUM: Espécie do animal\n// ============================================================\nenum Species {\n  DOG\n  CAT\n  BIRD\n  RABBIT\n  FISH\n  REPTILE\n  OTHER\n}\n\n// ============================================================\n// ENUM: Sexo do animal\n// ============================================================\nenum PetGender {\n  MALE\n  FEMALE\n  UNKNOWN\n}\n\n// ============================================================\n// MODEL: User\n// Representa o tutor responsável pelos pets\n// ============================================================\nmodel User {\n  id        String  @id @default(uuid())\n  name      String  @db.VarChar(100)\n  email     String  @unique @db.VarChar(150)\n  password  String  @db.VarChar(255) // hash bcrypt\n  phone     String? @db.VarChar(20)\n  avatarUrl String? @db.VarChar(500)\n  isActive  Boolean @default(true)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // Relacionamentos\n  pets Pet[]\n\n  @@map(\"users\")\n}\n\n// ============================================================\n// MODEL: Pet\n// Animal de estimação vinculado a um tutor\n// ============================================================\nmodel Pet {\n  id        String    @id @default(uuid())\n  name      String    @db.VarChar(100)\n  species   Species\n  breed     String?   @db.VarChar(100)\n  gender    PetGender @default(UNKNOWN)\n  birthDate DateTime? @db.Date\n  weight    Decimal?  @db.Decimal(5, 2) // em kg\n  color     String?   @db.VarChar(50)\n  microchip String?   @unique @db.VarChar(50)\n  photoUrl  String?   @db.VarChar(500)\n  notes     String?   @db.Text\n  isActive  Boolean   @default(true)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // FK → User\n  userId String\n  user   User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n\n  // Relacionamentos\n  careRecords CareRecord[]\n\n  // Índices para performance\n  @@index([userId])\n  @@index([species])\n  @@map(\"pets\")\n}\n\n// ============================================================\n// MODEL: CareRecord\n// Histórico cronológico de cuidados do pet\n// Suporta filtro por tipo, data e status\n// ============================================================\nmodel CareRecord {\n  id            String    @id @default(uuid())\n  type          CareType\n  title         String    @db.VarChar(200) // ex: \"Vacina antirrábica V10\"\n  description   String?   @db.Text\n  performedAt   DateTime // data/hora do cuidado (cronologia)\n  nextDueAt     DateTime? // próximo agendamento (ex: reforço)\n  veterinarian  String?   @db.VarChar(100) // nome do veterinário\n  clinic        String?   @db.VarChar(150) // nome da clínica\n  cost          Decimal?  @db.Decimal(8, 2) // custo em reais\n  attachmentUrl String?   @db.VarChar(500) // link de laudo/receita\n  batchNumber   String?   @db.VarChar(50) // lote (relevante para vacinas)\n  dosage        String?   @db.VarChar(100) // dosagem (relevante para medicamentos)\n  isCompleted   Boolean   @default(true)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  // FK → Pet\n  petId String\n  pet   Pet    @relation(fields: [petId], references: [id], onDelete: Cascade)\n\n  // Índices para filtros e ordenação cronológica\n  @@index([petId])\n  @@index([type])\n  @@index([performedAt]) // ORDER BY performedAt DESC\n  @@index([petId, type]) // filtro composto: pet + tipo\n  @@index([petId, performedAt]) // histórico cronológico por pet\n  @@index([nextDueAt]) // alertas de próximos cuidados\n  @@map(\"care_records\")\n}\n",
